//B. Numbers Box #include<bits/stdc++.h>using namespace std;#define int long long intsigned main(){    int t;    cin>>t;    while(t--){        int n,m;        cin>>n>>m;        int arr[n][m];        int sum=0,ne=0;        int mini=99999999999;        for(int i=0;i<n;i++){            for(int j=0;j<m;j++){                cin>>arr[i][j];                sum=sum+abs(arr[i][j]);                if(arr[i][j]<0){                    ne++;                }                if(abs(arr[i][j])<mini){                    mini=abs(arr[i][j]);                }            }        }                if(ne%2==0){            cout<<sum<<endl;        }        else{            cout<<sum-2*abs(mini)<<endl;        }    }}